('ph-ml-foundations', NULL, 1, 'phase', NULL, NULL, NULL, 'Machine Learning Foundations and Role Context', 'Understand what machine learning engineers build, where ML fits in software products, and how supervised, unsupervised, and production ML workflows connect.', 'trunk', 22, 'beginner', '{"source": "roadmap.sh/machine-learning", "visualRole": "trunk"}'::jsonb, true, false, '["Explain the purpose of the Machine Learning Foundations and Role Context phase and its role in the full machine learning engineering path.", "Connect the phase topics to concrete machine learning engineering deliverables.", "Identify the artifacts or evidence needed before progressing."]'::jsonb, '["Summarize the key concepts covered in Machine Learning Foundations and Role Context.", "Identify completed and incomplete child topics or projects.", "Prepare notes or artifacts that show readiness for the next phase."]'::jsonb),
('grp-ml-role-and-workflow', 'ph-ml-foundations', 1, 'choice_group', NULL, 'complete_all', 5, 'ML Role and Workflow', 'Group topics for ML Role and Workflow inside Machine Learning Foundations and Role Context.', 'side', 9, 'beginner', '{"source": "roadmap.sh/machine-learning", "selectionType": "complete_all"}'::jsonb, true, false, '["Compare the options or grouped topics inside ML Role and Workflow.", "Select or complete the required children according to the group rule.", "Explain how the selected work supports practical machine learning engineering readiness."]'::jsonb, '["Complete the required number of child nodes for this group.", "Document why the selected options fit the learner''s target direction or project needs.", "Confirm that required child projects or topics have reviewable evidence."]'::jsonb),
